SELECT t.id, t.policy_id, t.model_id, m.model_name, p.provider_name, t.priority, t.status FROM ai_model_route_target t JOIN ai_model m ON m.id = t.model_id AND m.del_flag = '0' JOIN ai_provider p ON p.id = m.provider_id AND p.del_flag = '0' WHERE t.policy_id IN
#{policyId}
AND t.del_flag = '0' ORDER BY t.policy_id ASC, t.priority ASC, t.id ASC
